173	  render(): React.ReactNode {
174	    const scaleInfo = this.scaledAxisInfo(this.props.data);
175	    const fullLegendData = this.buildFullLegendData();
176	    const filteredLegendData = this.buildFilteredLegendData(fullLegendData);
177	    const showMoreLegend = fullLegendData.length > filteredLegendData.length;
178	    const chartHeight = this.props.chartHeight ?? 300;
