  1	import * as React from 'react';
  2	import {
  3	  ChartAxis,
  4	  Chart,
  5	  ChartGroup,
  6	  ChartScatter,
  7	  ChartProps,
  8	  ChartTooltipProps,
  9	  ChartLabel,
 10	  ChartLegend,
 11	  ChartLine,
 12	  createContainer
 13	} from '@patternfly/react-charts';
 14	import { VictoryPortal } from 'victory-core';
 15	import { VictoryBoxPlot } from 'victory-box-plot';
 16	import { format as d3Format } from 'd3-format';
 17	import { getFormatter, getUnit } from 'utils/Formatter';
 18	import { VCLines, LegendItem, LineInfo, RichDataPoint, RawOrBucket, VCDataPoint } from 'types/VictoryChartInfo';
 19	import { Overlay } from 'types/Overlay';
 20	import { BrushHandlers, getVoronoiContainerProps } from './Container';
 21	import { toBuckets } from 'utils/VictoryChartsUtils';
 22	import { VCEvent, addLegendEvent } from 'utils/VictoryEvents';
 23	import { XAxisType } from 'types/Dashboards';
 24	import { CustomTooltip } from './CustomTooltip';
 25	import { INTERPOLATION_STRATEGY } from './SparklineChart';
 26	import { KialiIcon } from '../../config/KialiIcon';
 27	import { Button, ButtonVariant, Tooltip, TooltipPosition } from '@patternfly/react-core';
 28	import regression from 'regression';
 29	import { kialiStyle } from 'styles/StyleUtils';
 30	import { PFColors } from 'components/Pf/PfColors';
 31	import { VictoryVoronoiContainer } from 'victory-voronoi-container';
 32	
 33	type Props<T extends RichDataPoint, O extends LineInfo> = {
 34	  brushHandlers?: BrushHandlers;
 35	  chartHeight?: number;
 36	  data: VCLines<T & VCDataPoint>;
 37	  fill?: boolean;
 38	  groupOffset?: number;
 39	  isMaximized?: boolean;
 40	  labelComponent?: React.ReactElement<ChartTooltipProps>;
 41	  moreChartProps?: ChartProps;
 42	  onClick?: (datum: RawOrBucket<O>) => void;
 43	  onTooltipClose?: (datum: RawOrBucket<O>) => void;
 44	  onTooltipOpen?: (datum: RawOrBucket<O>) => void;
 45	  overlay?: Overlay<O>;
 46	  overrideSeriesComponentStyle?: boolean;
 47	  // The TracingScatter component needs a flag to indicate that the trace datapoint needs a mouse pointer
 48	  // It could be detected indirectly, but it's complicated and less clear, a new optional flag simplifies this logic
 49	  pointer?: boolean;
 50	  seriesComponent: React.ReactElement;
 51	  showSpans?: boolean;
 52	  showTrendline?: boolean;
 53	  sizeRatio?: number;
 54	  stroke?: boolean;
 55	  timeWindow?: [Date, Date];
 56	  unit: string;
 57	  xAxis?: XAxisType;
 58	};
 59	
 60	type State = {
 61	  hiddenSeries: Set<string>;
 62	  showMoreLegend: boolean;
 63	  width: number;
 64	};
 65	
 66	type Padding = { bottom: number; left: number; right: number; top: number };
 67	
 68	type ScaleInfo = { count: number; format: string };
 69	
 70	const overlayName = 'overlay';
 71	
 72	const axisStyle = {
 73	  tickLabels: { fontSize: 12, padding: 2, fill: PFColors.Color100 },
 74	  grid: {
 75	    fill: 'none',
 76	    stroke: PFColors.ColorLight300,
 77	    strokeDasharray: '10, 5',
 78	    strokeLinecap: 'round',
 79	    strokeLinejoin: 'round',
 80	    pointerEvents: 'painted'
 81	  }
 82	};
 83	
 84	export const MIN_HEIGHT = 20;
 85	export const MIN_HEIGHT_YAXIS = 70;
 86	export const MIN_WIDTH = 275;
 87	export const LEGEND_HEIGHT = 25;
 88	const FONT_SIZE_LEGEND = 14;
 89	
 90	const moreLegendStyle = kialiStyle({
 91	  display: 'flex',
 92	  marginTop: '0.25rem',
 93	  marginLeft: 'auto'
 94	});
 95	
 96	const overlayLegendStyle = kialiStyle({
 97	  display: 'flex',
 98	  flexWrap: 'wrap',
 99	  flexDirection: 'column',
100	  position: 'relative',
101	  background: 'var(--pf-t--global--background--color--inverse--default)',
102	  opacity: 0.7,
103	  overflow: 'auto'
104	});
105	
106	const fullLegendStyle = kialiStyle({
107	  color: PFColors.White,
108	  margin: 'auto',
109	  $nest: {
110	    '& > div': {
111	      display: 'inline-block',
112	      marginRight: '0.25rem',
113	      width: '0.5rem',
114	      height: '0.5rem'
115	    }
116	  }
117	});
118	
119	export class ChartWithLegend<T extends RichDataPoint, O extends LineInfo> extends React.Component<Props<T, O>, State> {
120	  containerRef: React.RefObject<HTMLDivElement>;
121	  hoveredItem?: VCDataPoint;
122	  mouseOnLegend = false;
123	
124	  constructor(props: Props<T, O>) {
125	    super(props);
126	    this.containerRef = React.createRef<HTMLDivElement>();
127	    this.state = {
128	      width: 0,
129	      hiddenSeries: new Set([overlayName]),
130	      showMoreLegend: false
131	    };
132	  }
133	
134	  componentDidMount(): void {
135	    setTimeout(() => {
136	      this.handleResize();
137	      window.addEventListener('resize', this.handleResize);
138	    });
139	  }
140	
141	  componentWillUnmount(): void {
142	    window.removeEventListener('resize', this.handleResize);
143	  }
144	
145	  private onTooltipClose = (): void => {
146	    if (this.props.onTooltipClose) {
147	      this.props.onTooltipClose(this.hoveredItem as RawOrBucket<O>);
148	    }
149	
150	    this.hoveredItem = undefined;
151	  };
152	
153	  private onTooltipOpen = (points?: VCDataPoint[]): void => {
154	    if (points && points.length > 0) {
155	      this.hoveredItem = points[0];
156	    } else {
157	      this.hoveredItem = undefined;
158	    }
159	
160	    if (this.props.onTooltipOpen) {
161	      this.props.onTooltipOpen(this.hoveredItem as RawOrBucket<O>);
162	    }
163	  };
164	
165	  private onShowMoreLegend = (): void => {
166	    this.setState(prevState => {
167	      return {
168	        showMoreLegend: !prevState.showMoreLegend
169	      };
170	    });
171	  };
172	
173	  render(): React.ReactNode {
174	    const scaleInfo = this.scaledAxisInfo(this.props.data);
175	    const fullLegendData = this.buildFullLegendData();
176	    const filteredLegendData = this.buildFilteredLegendData(fullLegendData);
177	    const showMoreLegend = fullLegendData.length > filteredLegendData.length;
178	    const chartHeight = this.props.chartHeight ?? 300;
179	    const overlayIdx = this.props.data.length;
180	    const showOverlay = (this.props.overlay && this.props.showSpans) ?? false;
181	    const overlayRightPadding = showOverlay ? 15 : 0;
182	
183	    const padding: Padding = {
184	      top: 0,
185	      bottom: chartHeight > MIN_HEIGHT_YAXIS ? LEGEND_HEIGHT : 0,
186	      left: 0,
187	      right: 10 + overlayRightPadding
188	    };
189	
190	    const events: VCEvent[] = [];
191	
192	    if (this.props.onClick) {
193	      events.push({
194	        target: 'parent',
195	        eventHandlers: {
196	          onClick: () => {
197	            if (this.hoveredItem) {
198	              this.props.onClick!(this.hoveredItem as RawOrBucket<O>);
199	            }
200	            return [];
201	          }
202	        }
203	      });
204	    }
205	
206	    this.props.data.forEach((s, idx) =>
207	      this.registerEvents(events, idx, [`serie-${idx}`, `serie-reg-${idx}`], s.legendItem.name)
208	    );
209	
210	    let useSecondAxis = showOverlay;
211	    let normalizedOverlay: RawOrBucket<O>[] = [];
212	    let overlayFactor = 1.0;
213	
214	    const mainMax = Math.max(...this.props.data.map(line => Math.max(...line.datapoints.map(d => d.y))));
215	
216	    if (this.props.overlay) {
217	      this.registerEvents(events, overlayIdx, [overlayName], overlayName);
218	      // Normalization for y-axis display to match y-axis domain of the main data
219	      // (see https://formidable.com/open-source/victory/gallery/multiple-dependent-axes/)
220	      const overlayMax = Math.max(...this.props.overlay.vcLine.datapoints.map(d => d.y));
221	
222	      if (overlayMax !== 0) {
223	        overlayFactor = mainMax / overlayMax;
224	      }
225	
226	      if (this.props.unit === this.props.overlay.info.lineInfo.unit && overlayFactor > 0.5 && overlayFactor < 2) {
227	        // Looks like it's fine to re-use the existing axis
228	        useSecondAxis = false;
229	        overlayFactor = 1.0;
230	      }
231	
232	      normalizedOverlay = this.normalizeOverlay(overlayFactor);
233	
234	      if (this.props.overlay.info.buckets) {
235	        // Transform to bucketed stats
236	        const model: O = { ...this.props.overlay.info.lineInfo, scaleFactor: overlayFactor };
237	        normalizedOverlay = toBuckets(
238	          this.props.overlay.info.buckets,
239	          normalizedOverlay as (VCDataPoint & O)[],
240	          model,
241	          this.props.timeWindow
242	        );
243	      }
244	    }
245	
246	    const tooltipHooks = { onOpen: this.onTooltipOpen, onClose: this.onTooltipClose };
247	
248	    const labelComponent = this.props.labelComponent ? (
249	      React.cloneElement(this.props.labelComponent as any, tooltipHooks)
250	    ) : (
251	      <CustomTooltip showTime={true} {...tooltipHooks} />
252	    );
253	
254	    const filteredData = this.props.data.filter(s => !this.state.hiddenSeries.has(s.legendItem.name));
255	
256	    const voronoiProps = getVoronoiContainerProps(labelComponent, () => this.mouseOnLegend);
257	
258	    let containerComponent: React.ReactElement;
259	
260	    if (this.props.brushHandlers) {
261	      const VoronoiBrushContainer = createContainer('brush', 'voronoi');
262	
263	      containerComponent = (
264	        <VoronoiBrushContainer
265	          brushDimension={'x'}
266	          brushDomain={{ x: [0, 0] }}
267	          brushStyle={{ stroke: 'transparent', fill: 'blue', fillOpacity: 0.1 }}
268	          defaultBrushArea={'none'}
269	          onBrushCleared={this.props.brushHandlers.onCleared}
270	          onBrushDomainChange={this.props.brushHandlers.onDomainChange}
271	          onBrushDomainChangeEnd={this.props.brushHandlers.onDomainChangeEnd}
272	          {...voronoiProps}
273	        />
274	      );
275	    } else {
276	      containerComponent = <VictoryVoronoiContainer {...voronoiProps} />;
277	    }
278	
279	    const chart = (
280	      <div ref={this.containerRef} style={{ marginTop: 0, height: chartHeight }}>
281	        <Chart
282	          width={this.state.width}
283	          padding={padding}
284	          events={events as any[]}
285	          height={chartHeight}
286	          containerComponent={containerComponent}
287	          scale={{ x: this.props.xAxis === 'series' ? 'linear' : 'time', y: 'linear' }}
288	          // Hack: Need at least 1 pxl on Y domain padding to prevent harsh clipping (https://github.com/kiali/kiali/issues/2069)
289	          // Hack: Chart points on the very edges are not clickable due to extra padding and the chart
290	          // not resizing correctly for some reason. The additional domain padding squeezes the elements
291	          // into the chart so that they are no longer on the edges (https://github.com/kiali/kiali/issues/5222).
292	          domainPadding={{ y: 10, x: this.props.xAxis === 'series' ? 50 : 15 }}
293	          {...this.props.moreChartProps}
294	        >
295	          {
296	            // Use width to change style of the x series supporting narrow scenarios
297	            this.props.xAxis === 'series' ? (
298	              <ChartAxis
299	                domain={[0, filteredData.length + 1]}
300	                style={axisStyle}
301	                tickValues={filteredData.map(s => s.legendItem.name)}
302	                tickFormat={() => ''}
303	              />
304	            ) : this.state.width <= MIN_WIDTH ? (
305	              <ChartAxis
306	                tickCount={scaleInfo.count}
307	                style={axisStyle}
308	                domain={this.props.timeWindow}
309	                tickFormat={t => {
310	                  return `:${t.getMinutes()}`;
311	                }}
312	              />
313	            ) : (
314	              <ChartAxis tickCount={scaleInfo.count} style={axisStyle} domain={this.props.timeWindow} />
315	            )
316	          }
317	
318	          <ChartAxis
319	            tickLabelComponent={
320	              <VictoryPortal>
321	                <ChartLabel />
322	              </VictoryPortal>
323	            }
324	            dependentAxis={true}
325	            tickCount={chartHeight <= MIN_HEIGHT_YAXIS ? 1 : undefined}
326	            tickFormat={getFormatter(d3Format, this.props.unit)}
327	            label={getUnit(d3Format, this.props.unit, mainMax)}
328	            axisLabelComponent={
329	              <ChartLabel y={-10} x={-15} angle={0} renderInPortal={true} style={{ fill: PFColors.Color100 }} />
330	            }
331	            style={axisStyle}
332	          />
333	
334	          {useSecondAxis && this.props.overlay && (
335	            <ChartAxis
336	              dependentAxis={true}
337	              offsetX={this.state.width - overlayRightPadding}
338	              style={axisStyle}
339	              tickCount={chartHeight <= MIN_HEIGHT_YAXIS ? 1 : undefined}
340	              tickFormat={t => getFormatter(d3Format, this.props.overlay?.info.lineInfo.unit ?? '')(t / overlayFactor)}
341	              tickLabelComponent={<ChartLabel dx={15} textAnchor="start" />}
342	              label={getUnit(
343	                d3Format,
344	                this.props.overlay?.info.lineInfo.unit ?? '',
345	                Math.max(...this.props.overlay.vcLine.datapoints.map(d => d.y))
346	              )}
347	              axisLabelComponent={
348	                <ChartLabel
349	                  y={-10}
350	                  x={this.state.width}
351	                  angle={0}
352	                  renderInPortal={true}
353	                  style={{ fill: PFColors.Color100 }}
354	                />
355	              }
356	            />
357	          )}
358	
359	          {this.props.xAxis === 'series'
360	            ? this.renderCategories()
361	            : this.renderTimeSeries(chartHeight > MIN_HEIGHT_YAXIS ? chartHeight - LEGEND_HEIGHT : chartHeight)}
362	
363	          {showOverlay &&
364	            (this.props.overlay!.info.buckets ? (
365	              <VictoryBoxPlot
366	                key="overlay"
367	                name={overlayName}
368	                data={normalizedOverlay}
369	                style={{
370	                  min: { stroke: this.props.overlay!.info.lineInfo.color, strokeWidth: 2 },
371	                  max: { stroke: this.props.overlay!.info.lineInfo.color, strokeWidth: 2 },
372	                  q1: { fill: this.props.overlay!.info.lineInfo.color },
373	                  q3: { fill: this.props.overlay!.info.lineInfo.color },
374	                  median: { stroke: 'white', strokeWidth: 2 }
375	                }}
376	              />
377	            ) : (
378	              <ChartScatter
379	                key="overlay"
380	                name={overlayName}
381	                data={normalizedOverlay}
382	                style={{ data: this.props.overlay!.info.dataStyle }}
383	              />
384	            ))}
385	
386	          {chartHeight > MIN_HEIGHT_YAXIS ? (
387	            <ChartLegend
388	              name="serie-legend"
389	              data={filteredLegendData}
390	              x={0}
391	              y={chartHeight}
392	              height={LEGEND_HEIGHT}
393	              width={this.state.width}
394	              style={{
395	                data: { cursor: 'pointer', padding: 0 },
396	                labels: { cursor: 'pointer', fontSize: FONT_SIZE_LEGEND, fill: PFColors.Color100 }
397	              }}
398	              borderPadding={{
399	                top: 5,
400	                left: 0,
401	                right: 0,
402	                bottom: 0
403	              }}
404	              symbolSpacer={5}
405	              gutter={{
406	                left: 0,
407	                right: 15
408	              }}
409	            />
410	          ) : undefined}
411	        </Chart>
412	
413	        {showMoreLegend && chartHeight > MIN_HEIGHT_YAXIS && (
414	          <Tooltip position={TooltipPosition.left} content={<div style={{ textAlign: 'left' }}>Show full legend</div>}>
415	            <Button
416	              variant={ButtonVariant.link}
417	              className={moreLegendStyle}
418	              isInline
419	              onClick={() => this.onShowMoreLegend()}
420	            >
421	              <KialiIcon.MoreLegend />
422	            </Button>
423	          </Tooltip>
424	        )}
425	
426	        {this.state.showMoreLegend && (
427	          <div
428	            style={{
429	              width: this.state.width,
430	              height: chartHeight,
431	              top: -(chartHeight + LEGEND_HEIGHT)
432	            }}
433	            className={overlayLegendStyle}
434	          >
435	            {fullLegendData.map((ld: LegendItem, idx: number) => (
436	              <div key={`full_legend_${idx}`} className={fullLegendStyle}>
437	                <div style={{ backgroundColor: ld.symbol.fill }}></div>
438	                {ld.name}
439	              </div>
440	            ))}
441	          </div>
