538	  private renderCategories = (): React.ReactNode => {
539	    let domainX = 1;
540	    const nbSeries = this.props.data.length - this.state.hiddenSeries.size;
541	    const size = ((this.props.sizeRatio ?? 1) * this.state.width) / Math.max(nbSeries, 1);
542	
543	    return this.props.data.map((serie, idx) => {
544	      if (this.state.hiddenSeries.has(serie.legendItem.name)) {
545	        return undefined;
546	      }
547	
548	      return React.cloneElement(
549	        this.props.seriesComponent,
550	        this.withStyle(
551	          {
552	            key: `serie-${idx}`,
553	            name: `serie-${idx}`,
554	            data: serie.datapoints.map(d => ({ size: size, ...d, x: domainX++ })),
555	            barWidth: size
556	          },
557	          serie.color
558	        )
559	      );
560	    });
561	  };
