400	                left: 0,
401	                right: 0,
402	                bottom: 0
403	              }}
404	              symbolSpacer={5}
405	              gutter={{
406	                left: 0,
407	                right: 15
408	              }}
409	            />
410	          ) : undefined}
411	        </Chart>
412	
413	        {showMoreLegend && chartHeight > MIN_HEIGHT_YAXIS && (
414	          <Tooltip position={TooltipPosition.left} content={<div style={{ textAlign: 'left' }}>Show full legend</div>}>
415	            <Button
416	              variant={ButtonVariant.link}
417	              className={moreLegendStyle}
418	              isInline
419	              onClick={() => this.onShowMoreLegend()}
420	            >
421	              <KialiIcon.MoreLegend />
422	            </Button>
423	          </Tooltip>
424	        )}
425	
426	        {this.state.showMoreLegend && (
427	          <div
428	            style={{
429	              width: this.state.width,
430	              height: chartHeight,
431	              top: -(chartHeight + LEGEND_HEIGHT)
432	            }}
433	            className={overlayLegendStyle}
434	          >
435	            {fullLegendData.map((ld: LegendItem, idx: number) => (
436	              <div key={`full_legend_${idx}`} className={fullLegendStyle}>
437	                <div style={{ backgroundColor: ld.symbol.fill }}></div>
438	                {ld.name}
439	              </div>
440	            ))}
441	          </div>
442	        )}
443	      </div>
444	    );
445	
446	    return chartHeight > MIN_HEIGHT ? (
447	      chart
448	    ) : (
449	      <div>
450	        <Tooltip
451	          position={TooltipPosition.right}
452	          content={<div style={{ textAlign: 'left' }}>Increase height of the chart</div>}
453	        >
454	          <Button variant={ButtonVariant.link} isInline>
455	            <KialiIcon.MoreLegend />
456	          </Button>
457	        </Tooltip>
458	      </div>
459	    );
460	  }
461	
462	  private renderTimeSeries = (height: number): React.ReactNode => {
463	    const groupOffset = this.props.groupOffset ?? 0;
464	
465	    return (
466	      <ChartGroup offset={groupOffset} height={height}>
467	        {this.props.data
468	          .map((serie, idx) => {
469	            if (this.state.hiddenSeries.has(serie.legendItem.name)) {
470	              return undefined;
471	            }
472	
473	            const plot = React.cloneElement(
474	              this.props.seriesComponent,
475	              this.withStyle(
476	                {
477	                  key: `serie-${idx}`,
478	                  name: `serie-${idx}`,
479	                  data: serie.datapoints,
480	                  interpolation: INTERPOLATION_STRATEGY
481	                },
482	                serie.color
483	              )
484	            );
485	
486	            // serie.datapoints may contain undefined values in certain scenarios i.e. "unknown" values
487	            if (this.props.showTrendline === true && serie.datapoints[0]) {
488	              const first_dpx = (serie.datapoints[0].x as Date).getTime() / 1000;
489	
490	              const datapoints = serie.datapoints.map(d => {
491	                let t = ((d.x as Date).getTime() / 1000 - first_dpx) / 10000;
492	                let trendPoint = parseFloat(d.y.toString());
493	
494	                if (d.y0) {
495	                  // If both reporters are enabled, generate the trend line using
496	                  // the mean values of both reporters
497	                  trendPoint += parseFloat(d.y0.toString());
498	                  trendPoint *= 0.5;
499	                }
500	
501	                // Array is [time, y];
502	                return [t, trendPoint];
503	              });
504	
505	              const linearRegression = regression.linear(datapoints, { precision: 10 });
506	
507	              let regressionDatapoints = serie.datapoints.map(d => ({
508	                ...d,
509	                name: `${d.name} (trendline)`,
510	                y: linearRegression.predict(((d.x as Date).getTime() / 1000 - first_dpx) / 10000)[1],
511	                y0: undefined // Clear y0, in case it is set to prevent the tooltip showing this value.
512	              }));
513	
514	              const regressionPlot = React.cloneElement(
515	                <ChartLine />, // Trend lines are always line charts.
516	                this.withStyle(
517	                  {
518	                    key: `serie-reg-${idx}`,
519	                    name: `serie-reg-${idx}`,
520	                    data: regressionDatapoints,
521	                    interpolation: INTERPOLATION_STRATEGY
522	                  },
523	                  serie.color,
524	                  true
525	                )
526	              );
527	
528	              return [plot, regressionPlot];
529	            }
530	
531	            return [plot];
532	          })
533	          .flat()}
534	      </ChartGroup>
535	    );
536	  };
537	
538	  private renderCategories = (): React.ReactNode => {
539	    let domainX = 1;
540	    const nbSeries = this.props.data.length - this.state.hiddenSeries.size;
541	    const size = ((this.props.sizeRatio ?? 1) * this.state.width) / Math.max(nbSeries, 1);
542	
543	    return this.props.data.map((serie, idx) => {
544	      if (this.state.hiddenSeries.has(serie.legendItem.name)) {
545	        return undefined;
546	      }
547	
548	      return React.cloneElement(
549	        this.props.seriesComponent,
550	        this.withStyle(
551	          {
552	            key: `serie-${idx}`,
553	            name: `serie-${idx}`,
554	            data: serie.datapoints.map(d => ({ size: size, ...d, x: domainX++ })),
555	            barWidth: size
556	          },
557	          serie.color
558	        )
559	      );
560	    });
561	  };
562	
563	  private withStyle = (
564	    props: { [key: string]: unknown },
565	    color?: string,
566	    strokeDasharray?: boolean
567	  ): { [key: string]: unknown } => {
568	    return this.props.overrideSeriesComponentStyle === false
569	      ? props
570	      : {
571	          ...props,
572	          style: {
573	            data: {
574	              fill: this.props.fill ? color : undefined,
575	              stroke: this.props.stroke ? color : undefined,
576	              strokeDasharray: strokeDasharray === true ? '3 5' : undefined,
577	              cursor: this.props.pointer ? 'pointer' : 'default'
578	            }
579	          }
580	        };
581	  };
582	
583	  private handleResize = (): void => {
584	    if (this.containerRef && this.containerRef.current) {
585	      this.setState({ width: this.containerRef.current.clientWidth });
586	    }
587	  };
588	
589	  private buildFullLegendData = (): LegendItem[] => {
590	    return this.props.data.map(s => {
591	      const name = s.legendItem.name;
592	
593	      if (this.state.hiddenSeries.has(s.legendItem.name)) {
594	        return { name, symbol: { ...s.legendItem.symbol, fill: PFColors.Color200 } };
595	      }
596	
597	      return { ...s.legendItem, name };
598	    });
599	  };
600	
601	  private buildFilteredLegendData = (fullLegendData: LegendItem[]): LegendItem[] => {
602	    // 30px == "more legend" left button width
603	    // 10px == "more legend" left padding
604	    const maxWidth = this.state.width - 30 - 10;
605	    const filtered: LegendItem[] = [];
606	    let currentWidth = 0;
607	
608	    for (let i = 0; i < fullLegendData.length; i++) {
609	      const item = fullLegendData[i];
610	      // 12px == legend icon + space
611	      // 7px == char size
612	      // 15px == right padding
613	      currentWidth += 12 + item.name.length * 7 + 15;
614	
615	      if (currentWidth >= maxWidth) {
616	        break;
617	      }
618	
619	      filtered.push(item);
620	    }
621	
622	    return filtered;
623	  };
624	
625	  private registerEvents = (events: VCEvent[], idx: number, serieID: string[], serieName: string): void => {
626	    addLegendEvent(events, {
627	      legendName: 'serie-legend',
628	      idx: idx,
629	      serieID: serieID,
630	      onClick: () => {
631	        if (!this.state.hiddenSeries.delete(serieName)) {
632	          // Was not already hidden => add to set
633	          this.state.hiddenSeries.add(serieName);
634	        }
635	
636	        this.setState({ hiddenSeries: new Set(this.state.hiddenSeries) });
637	        return null;
638	      }
639	    });
640	  };
641	
642	  private scaledAxisInfo = (data: VCLines<VCDataPoint & T>): ScaleInfo => {
643	    const ticks = Math.max(...data.map(s => s.datapoints.length));
644	
645	    if (this.state.width < 500) {
646	      return {
647	        count: Math.min(5, ticks),
648	        format: '%H:%M'
649	      };
650	    } else if (this.state.width < 700) {
651	      return {
652	        count: Math.min(10, ticks),
653	        format: '%H:%M'
654	      };
655	    }
656	
657	    return {
658	      count: Math.min(15, ticks),
659	      format: '%H:%M:%S'
660	    };
661	  };
662	
663	  private normalizeOverlay = (factor: number): (VCDataPoint & O)[] => {
664	    // All data is relative to the first Y-axis, even if a second one is in use
665	    // To make it appear as relative to the second axis, we need to normalize it, ie. apply the same scale factor that exists between the two axis
666	    // This scale factor is stored in every datapoint so that it can be "reverted" when we need to retrieve the original value, e.g. in tooltips
667	    return this.props.overlay!.vcLine.datapoints.map(dp => ({ ...dp, y: dp.y * factor, scaleFactor: factor }));
668	  };
669	}

